args.sparql:
SELECT ?attendance
WHERE {
  ?game wdt:P1208 ?competition .
  ?competition rdfs:label "National League Championship Series"@en .
  { ?game wdt:P502 wd:Q144 ; wdt:P515 wd:Q102353 . }
  UNION
  { ?game wdt:P502 wd:Q102353 ; wdt:P515 wd:Q144 . }
  ?game wdt:P585 ?date .
  BIND(YEAR(?date) AS ?year)
  VALUES ?year { 1977 1978 2008 2009 }
  ?game wdt:P753 ?duration .
  ?game wdt:P245 ?attendance .
}
ORDER BY ?duration
OFFSET 4
LIMIT 1

